// src/App.js
import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Education from './components/Education';
import Tests from './components/Tests';
import Analysis from './components/Analysis'; // Убедитесь, что импортирован
import Trading from './components/Trading';

import './App.css';

function App() {
  const [activeTab, setActiveTab] = useState('education');
  const [progress, setProgress] = useState({ modules: {}, overall_progress: 0 });

  // --- НОВОЕ СОСТОЯНИЕ ДЛЯ ПРОГРЕССА ПО ТЕСТАМ ---
  const [testProgress, setTestProgress] = useState({ modules: {}, overall_test_progress: 0 });

  const [tradingState, setTradingState] = useState({
    balance: 10000,
    positions: 0,
    tradeLog: []
  });
  const [isSidebarHidden, setIsSidebarHidden] = useState(false);

  // --- useEffect для загрузки ОБОИХ прогрессов ---
  useEffect(() => {
    const savedProgress = localStorage.getItem('progress');
    if (savedProgress) {
      try {
        const parsedProgress = JSON.parse(savedProgress);
        setProgress(parsedProgress);
      } catch (error) {
        console.error("Ошибка при загрузке прогресса из localStorage:", error);
        setProgress({ modules: {}, overall_progress: 0 });
      }
    }

    // Загрузка прогресса по тестам
    const savedTestProgress = localStorage.getItem('testProgress');
    if (savedTestProgress) {
      try {
        const parsedTestProgress = JSON.parse(savedTestProgress);
        setTestProgress(parsedTestProgress);
      } catch (error) {
        console.error("Ошибка при загрузке прогресса по тестам из localStorage:", error);
        setTestProgress({ modules: {}, overall_test_progress: 0 });
      }
    }
  }, []);

  // --- useEffect для сохранения прогресса ОБУЧЕНИЯ ---
  useEffect(() => {
    localStorage.setItem('progress', JSON.stringify(progress));
  }, [progress]);

  // --- useEffect для сохранения прогресса ПО ТЕСТАМ ---
  useEffect(() => {
    localStorage.setItem('testProgress', JSON.stringify(testProgress));
  }, [testProgress]);

  const switchTab = (tabName) => {
    setActiveTab(tabName);
  };

  const toggleRead = (moduleName, isChecked) => {
    setProgress(prevProgress => {
      const updatedModules = {
        ...prevProgress.modules,
        [moduleName]: isChecked
      };
      const completedCount = Object.values(updatedModules).filter(Boolean).length;
      const overall = Math.round((completedCount / Object.keys(modules).length) * 100);
      return {
        modules: updatedModules,
        overall_progress: overall
      };
    });
  };

  // --- НОВАЯ ФУНКЦИЯ ДЛЯ ОБНОВЛЕНИЯ ПРОГРЕССА ПО ТЕСТАМ ---
  const updateTestProgress = (moduleName, passed) => {
    setTestProgress(prevProgress => {
      const updatedModules = {
        ...prevProgress.modules,
        [moduleName]: passed
      };
      const passedCount = Object.values(updatedModules).filter(Boolean).length;
      const overall = Math.round((passedCount / Object.keys(modules).length) * 100);
      return {
        modules: updatedModules,
        overall_test_progress: overall
      };
    });
  };

  const loadData = (parsedData) => {
    // App.js может логировать или обрабатывать данные, если нужно
    // console.log("Данные получены в App.js:", parsedData);
  };

  const handleBuyOrder = (amount, price) => {
    setTradingState(prevState => {
        const cost = amount * price;
        if (cost > prevState.balance) {
            alert('Недостаточно средств');
            return prevState; // Не обновляем состояние
        }
        return {
            balance: prevState.balance - cost,
            positions: prevState.positions + amount,
            tradeLog: [...prevState.tradeLog, `Куплено ${amount} по ${price.toFixed(2)}`]
        };
    });
  };

  const handleSellOrder = (amount, price) => {
    setTradingState(prevState => {
        if (amount > prevState.positions) {
            alert('Недостаточно позиций для продажи');
            return prevState; // Не обновляем состояние
        }
        return {
            balance: prevState.balance + (amount * price),
            positions: prevState.positions - amount,
            tradeLog: [...prevState.tradeLog, `Продано ${amount} по ${price.toFixed(2)}`]
        };
    });
  };

  const toggleSidebar = () => {
    setIsSidebarHidden(!isSidebarHidden);
  };


  // --- ВАЖНО: Обновленный объект modules с HTML-разметкой ---
  // src/App.js (объект modules)

// src/App.js (объект modules)

const modules = {
  "Начало начал": {
    title: "Трейдинг и его основы",
    content: `<h2>Трейдинг и его основы</h2>
<p>Трейдинг представляет собой деятельность по покупке и продаже различных финансовых активов с целью получения прибыли. Этот процесс основан на анализе рыночных условий и прогнозировании будущих ценовых движений. Чтобы успешно участвовать в этом процессе, необходимо сначала освоить базовые понятия и правила безопасности.</p>

<h3>Финансовые рынки</h3>
<p>Финансовые рынки, где происходит торговля, можно классифицировать на несколько основных типов:</p>
<ul>
<li><strong>Рынок акций (stocks)</strong> — торговля долями (акциями) компаний, таких как Apple или Microsoft.</li>
<li><strong>Рынок облигаций (bonds)</strong> — торговля долговыми обязательствами.</li>
<li><strong>Валютный рынок (forex)</strong> — обмен одной валюты на другую (например, EUR/USD). Является крупнейшим в мире.</li>
<li><strong>Рынок производных инструментов (derivatives)</strong> — торговля контрактами, стоимость которых зависит от базового актива (фьючерсы, опционы).</li>
</ul>

<h3>Понятие "лот" и "позиция"</h3>
<p>Центральным элементом любой торговой операции является понятие <em>«лот»</em>. Лот представляет собой фиксированный объем торгового инструмента, который определяет размер прибыли или убытка за каждую единицу изменения цены. Например, если вы торгуете лотом акций, вы не можете купить одну акцию; вы должны совершить транзакцию минимальным доступным объемом, который и называется лотом. Размер лота напрямую влияет на вашу <em>позицию</em>, то есть на общее количество активов, которое вы намерены купить или продать в рамках одной сделки. Понимание этого термина критически важно, поскольку от него зависит масштаб ваших потенциальных доходов и убытков.</p>

<h3>Типы ордеров</h3>
<p>Механика торговли также включает использование различных типов ордеров, которые являются инструкциями для брокера о том, как выполнять сделки. Наиболее распространенным является <em>рыночный ордер</em>, который выполняется немедленно по текущей рыночной цене. Однако для управления рисками трейдеры часто используют <em>стоп-приказ</em> (<em>стоп-лосс</em>). Это ордер, который закрывает позицию по рыночной цене после того, как цена достигнет заранее установленного уровня убыточности. Например, если вы купили акцию по 100 долларов и опасаетесь её падения, вы можете установить стоп-лосс на уровне 95 долларов. Если цена упадёт до этой отметки, ваша позиция будет автоматически продана, ограничивая ваш убыток на уровне 5 долларов на акцию. Использование стоп-приказов является одним из ключевых правил безопасной торговли.</p>

<h3>Управление капиталом</h3>
<p>Еще один фундаментальный принцип — это <em>управление капиталом</em>, в частности, адаптация <em>размера позиции</em>. <em>Размер позиции</em> — это количество активов, которое вы готовы купить или продать. Он должен рассчитываться исходя из вашего риска и общего капитала на счёте. Трейдеры должны использовать стоп-приказы для ограничения потенциальных убытков. Кроме того, важен принцип <em>соотношения риска к прибыли</em>. Перед входом в сделку трейдер должен иметь чёткое представление о потенциальной прибыли и потенциальном убытке, стремясь к тому, чтобы потенциальная прибыль была больше, чем потенциальный убыток. Некоторые эксперты рекомендуют, чтобы стоп-лосс не был установлен ближе чем в 1,5 раза к текущему диапазону высокой/низкой цены (волатильности), так как более близко расположенный стоп-лосс с высокой вероятностью будет сработан без веских причин.</p>
<p>Эти базовые правила — использование стоп-приказов, адаптация размера позиции и положительное соотношение риска к прибыли — формируют основу безопасной и дисциплинированной торговой стратегии, которая позволяет выживать на рынке в долгосрочной перспективе.</p>

<h2>Справка по ключевым терминам</h2>
<dl>
<dt>Трейдинг</dt>
<dd>Деятельность по покупке и продаже финансовых активов с целью получения прибыли на основе анализа рынка и прогнозирования ценовых движений.</dd>

<dt>Финансовые рынки</dt>
<dd>Площадки, где совершаются сделки с финансовыми инструментами. Основные типы: Рынок акций, Рынок облигаций, Валютный рынок (Forex), Рынок производных инструментов.</dd>

<dt>Лот</dt>
<dd>Стандартный или минимальный объём торгового инструмента, в котором совершается сделка. Определяет масштаб потенциальной прибыли или убытка.</dd>

<dt>Позиция</dt>
<dd>Объём актива, который трейдер купил («длинная позиция») или продал в расчёте на будущий выкуп («короткая позиция»). Характеризует текущее участие на рынке.</dd>

<dt>Ордер</dt>
<dd>Инструкция брокеру на совершение сделки. Основные виды: Рыночный ордер, Стоп-приказ (стоп-лосс).</dd>

<dt>Управление капиталом</dt>
<dd>Стратегия распределения средств на торговых операциях с учётом рисков и размера депозита.</dd>

<dt>Размер позиции</dt>
<dd>Количество единиц актива, которое трейдер решает купить или продать. Рассчитывается на основе допустимого риска и уровня стоп-лосса.</dd>

<dt>Соотношение «риск/прибыль»</dt>
<dd>Соотношение потенциального убытка к потенциальной прибыли по сделке. Рекомендуется, чтобы возможная прибыль превышала возможный убыток (например, 1:2 или лучше).</dd>

<dt>Волатильность</dt>
<dd>Мера изменчивости цены актива за определённый период. Высокая волатильность означает большие колебания цены.</dd>
</dl>`,
questions: [ // <-- ВОПРОСЫ ТЕПЕРЬ ВНУТРИ МОДУЛЯ
        { q: "Что такое трейдинг?", a: ["Покупка и продажа активов", "Игра в карты", "Спорт"], correct: 0 },
        { q: "Что такое рынок?", a: ["Место обмена товарами", "Парк", "Магазин"], correct: 0 }
      ]
  },
"Введение в графики": {
  title: "Основы свечей, объемов и чтения графиков",
  content: `<h2>Основы свечей и чтения графиков</h2>
<p>Центральным инструментом для анализа рынка в трейдинге является <em>график</em>, который представляет собой визуальное отображение ценовых движений во времени. Наиболее популярным и информативным типом графиков являются <em>свечные</em>, которые предоставляют богатую информацию о поведении рынка за определённый период.</p>

<h3>Что такое свеча?</h3>
<p>Каждая свеча на графике содержит <strong>четыре ключевые ценовые точки</strong>:</p>
<ol>
<li><strong>Open (цена открытия)</strong></li>
<li><strong>High (максимум)</strong></li>
<li><strong>Low (минимум)</strong></li>
<li><strong>Close (цена закрытия)</strong></li>
</ol>
<p>Эти данные соответствуют выбранному <em>временному интервалу</em> (таймфрейму), например, 1 минута, 1 час, 1 день.</p>

<h3>Структура свечи</h3>
<p>Свеча состоит из двух основных частей:</p>
<img src="/images/svechi.png" alt="Структура бычьей и медвежьей свечи" style="display: block; margin: 20px auto; max-width: 80%; height: auto; border-radius: 6px; box-shadow: 0 4px 8px rgba(0,0,0,0.1);">

<ul>
<li><strong>Тело</strong> — это прямоугольная часть свечи, соединяющая <em>цену открытия</em> и <em>цену закрытия</em>. Цвет тела (обычно зелёный или белый для <em>бычьей</em> свечи, красный или чёрный для <em>медвежьей</em>) указывает на направление движения цены за период.
<ul>
<li><em>Бычья свеча</em>: цена закрытия выше цены открытия — указывает на рост.</li>
<li><em>Медвежья свеча</em>: цена закрытия ниже цены открытия — указывает на падение.</li>
</ul>
Длина тела показывает силу доминирования: длинное тело говорит о сильном импульсе покупателей или продавцов, короткое — о равенстве сил или неопределённости.</li>
<li><strong>Тени (или «вьюшки»)</strong> — это тонкие линии над и под телом свечи:
<ul>
<li><em>Верхняя тень</em> соединяет <em>максимум</em> с верхней границей тела.</li>
<li><em>Нижняя тень</em> соединяет <em>минимум</em> с нижней границей тела.</li>
</ul>
Длинная верхняя тень указывает, что цена поднималась высоко, но столкнулась с сопротивлением и закрылась значительно ниже пика — признак возможного ослабления быков. Длинная нижняя тень говорит о том, что цена падала глубоко, но покупатели смогли отбить её — признак потенциальной поддержки и возможного разворота вверх.</li>
</ul>

<h3>Другие типы графиков</h3>
<p>Помимо свечных графиков, существуют и другие типы:</p>
<ul>
<li><strong>Линейные графики</strong> — соединяют только точки закрытия, удобны для отслеживания общего тренда.</li>
<li><strong>Гистограммы</strong> — показывают только разницу между Open и Close, игнорируя High и Low.</li>
</ul>
<p>Однако именно свечные графики обеспечивают наиболее полную картину: они содержат все четыре ценовые точки и позволяют визуально оценить не только направление, но и силу движения, а также внутреннюю борьбу между покупателями и продавцами в каждом временном интервале. Понимание этих базовых элементов — обязательное условие для освоения более сложных техник, таких как анализ свечных и графических паттернов.</p>

<h2>Справка по ключевым терминам</h2>
<dl>
<dt>График</dt>
<dd>Визуальное представление изменения цены актива во времени.</dd>

<dt>Свечной график</dt>
<dd>График, где каждый период представлен «свечой» с четырьмя ценовыми точками (Open, High, Low, Close).</dd>

<dt>Тело свечи</dt>
<dd>Прямоугольная часть, соединяющая цену открытия и закрытия. Цвет и длина показывают направление и силу движения.</dd>

<dt>Тень (вьюшка)</dt>
<dd>Линия над/под телом, соединяющая экстремумы (High/Low) с границами тела. Указывает на давление противоположной стороны.</dd>

<dt>Бычья свеча</dt>
<dd>Зелёная/белая свеча: цена закрытия &gt; цены открытия → рост.</dd>

<dt>Медвежья свеча</dt>
<dd>Красная/чёрная свеча: цена закрытия &lt; цены открытия → падение.</dd>

<dt>Линейный график</dt>
<dd>Соединяет только цены закрытия; простой, но упрощённый — не показывает внутридневную волатильность.</dd>

<dt>Гистограмма</dt>
<dd>Показывает только разницу между Open и Close; не отражает максимумы и минимумы.</dd>

<dt>Временной интервал (таймфрейм)</dt>
<dd>Продолжительность одного периода на графике (1M, 5M, 1H, 1D и т.д.).</dd>
</dl>`
},
   "Свечные паттерны": {
    title: "Бычьи и медвежьи паттерны свечей",
    content: `<h2>Анализ рынка через свечные и графические паттерны</h2>
<p>Анализ свечных и графических паттернов является методом технического анализа, позволяющим трейдерам предсказывать будущие ценовые движения на основе предыдущих. Свечные паттерны состоят из одной, двух или трех свечей и указывают на потенциальные развороты тренда или его временную паузу. Графические паттерны, в свою очередь, формируются на протяжении более длительного времени и могут занимать от нескольких дней до нескольких месяцев, отражая сложную борьбу между покупателями и продавцами.</p>

<h3>Свечные паттерны</h3>
<p>Свечные паттерны делятся на бычьи и медвежьи.</p>

<ul>
<li><strong>Бычьи паттерны</strong>, такие как <em>"Хаммер"</em> (Hammer) и <em>"Утренняя звезда"</em> (Morning Star), обычно появляются после периода падения цены и сигнализируют о потенциальном окончании этого тренда и начале восстановления. Паттерн <em>"Хаммер"</em> имеет очень короткое тело в нижней части и длинную нижнюю тень, что указывает на то, что хотя цена падала, давление покупателей усилилось, и они смогли отбить снижение.</li>
<li><strong>Медвежьи паттерны</strong>, например, <em>"Звезда рассвета"</em> (Shooting Star) или <em>"Вечерняя звезда"</em> (Evening Star), появляются на пиках роста и предвещают разворот вниз.</li>
</ul>

<p>Важно понимать, что сам по себе паттерн является лишь сигналом, который требует подтверждения. Наиболее надежным способом подтверждения является анализ <em>объема торгов</em> (Volume). Если после бычьего паттерна, такого как Хаммер, следующая свеча формируется на повышенном объеме, это значительно усиливает сигнал о возможном развороте, так как подтверждает участие большого числа покупателей.</p>

<h3>Графические паттерны</h3>
<p>Графические паттерны также делятся на две большие группы: <em>разворотные</em> и <em>продолжения</em>.</p>

<ul>
<li><strong>Разворотные паттерны</strong> указывают на вероятное изменение существующего тренда. Классическим примером является паттерн <em>"Голова и Плечи"</em> (Head and Shoulders), который считается мощным сигналом медвежьего разворота. Он состоит из трех максимумов: левое плечо, голова (самый высокий максимум) и правое плечо. После формирования правого плеча цена часто пробивает <em>"шейную линию"</em> — горизонтальную линию, соединяющую минимумы между плечами и головой, что подтверждает разворот тренда. Другие разворотные паттерны включают <em>"Двойную Вершину"</em> (Double Top), где цена дважды не смогла преодолеть уровень сопротивления, и <em>"Тройное Дно"</em> (Triple Bottom), который сигнализирует о конце падения.</li>
<li><strong>Паттерны продолжения</strong>, или <em>трендовые</em>, предполагают лишь временную задержку в существующем движении перед его возобновлением. К ним относятся <em>флаги</em> (Flags), <em>пеннанты</em> (Pennants) и <em>треугольники</em> (Triangles). Треугольники образуются, когда уровни максимумов и минимумов сходятся, создавая сужающийся диапазон цен. Они могут иметь три варианта: восходящий, нисходящий и симметричный треугольник. Восходящий треугольник, имеющий горизонтальную верхнюю границу и восходящую нижнюю, обычно указывает на бычий разворот или продолжение бычьего тренда после пробоя вверх. Нисходящий треугольник, наоборот, предвещает медвежий разворот. Симметричный треугольник не имеет явного преимущества и может привести к пробою в любом направлении.</li>
</ul>

<p>Как и свечные паттерны, графические формации требуют подтверждения. Для разворотных паттернов таким подтверждением служит пробой ключевой линии (например, шейной линии у "Головы и Плеч") с увеличением объема. Для трендовых паттернов — пробой одной из сторон треугольника или флага. Без подтверждения эти паттерны могут оказаться ложными сигналами.</p>

